static int hex_char_to_nibble(char c) {
    if (c >= '0' && c <= '9') return c - '0';
    if (c >= 'a' && c <= 'f') return c - 'a' + 10;
    if (c >= 'A' && c <= 'F') return c - 'A' + 10;
    return -1;
}

static int parse_hex_string(const char *str, uint8_t *out, size_t max_len) {
    size_t slen = strlen(str);
    if (slen % 2 != 0 || slen / 2 > max_len) return -1;
    for (size_t i = 0; i < slen; i += 2) {
        int hi = hex_char_to_nibble(str[i]);
        int lo = hex_char_to_nibble(str[i + 1]);
        if (hi < 0 || lo < 0) return -1;
        out[i / 2] = (uint8_t)((hi << 4) | lo);
    }
    return (int)(slen / 2);
}

static int safe_parse_uint32(const char *str, uint32_t *out) {
    if (str == NULL || *str == '\0') return -1;

    uint32_t result = 0;
    const char *p = str;
    int base = 10;

    /* Check for hex prefix */
    if (p[0] == '0' && (p[1] == 'x' || p[1] == 'X')) {
        base = 16;
        p += 2;
        if (*p == '\0') return -1;
    }

    while (*p != '\0') {
        uint32_t digit;
        if (base == 16) {
            int n = hex_char_to_nibble(*p);
            if (n < 0) return -1;
            digit = (uint32_t)n;
        } else {
            if (*p < '0' || *p > '9') return -1;
            digit = (uint32_t)(*p - '0');
        }

        /* Overflow check */
        if (base == 16) {
            if (result > (UINT32_MAX >> 4)) return -1;
            result = (result << 4) | digit;
        } else {
            if (result > (UINT32_MAX - digit) / 10) return -1;
            result = result * 10 + digit;
        }
        p++;
    }

    *out = result;
    return 0;
}

