static void audit_log(audit_event_t event, uint32_t detail) {
    audit_entry_t entry;
    entry.timestamp = platform_get_time_sec();
    entry.event = event;
    entry.detail = detail;
    memcpy(entry.session_id, g_session.session_id, 4);

    /* Write to RAM ring buffer */
    uint32_t idx = g_audit_write_idx % DIAG_AUDIT_LOG_MAX_ENTRIES;
    g_audit_ring[idx] = entry;
    g_audit_write_idx++;

    /* Also persist to flash/EEPROM */
    platform_write_audit_log(&entry);
}

