static void session_reset(void) {
    uint32_t saved_attempts = g_session.auth_attempt_count;
    uint32_t saved_lockout = g_session.lockout_start_time;

    /* Clear sensitive session data */
    platform_secure_memzero(&g_session, sizeof(g_session));

    /* Preserve lockout state across session resets */
    g_session.auth_attempt_count = saved_attempts;
    g_session.lockout_start_time = saved_lockout;
    g_session.auth_state = AUTH_STATE_LOCKED;
    g_session.current_privilege = PRIV_NONE;
    g_session.jtag_unlocked = false;
}

static void session_full_reset(void) {
    platform_secure_memzero(&g_session, sizeof(g_session));
    g_session.auth_state = AUTH_STATE_LOCKED;
    g_session.current_privilege = PRIV_NONE;
    g_session.jtag_unlocked = false;
}

static bool session_is_locked_out(void) {
    if (g_session.auth_attempt_count >= DIAG_MAX_AUTH_ATTEMPTS) {
        uint32_t now = platform_get_time_sec();
        uint32_t elapsed = now - g_session.lockout_start_time;
        if (elapsed < DIAG_LOCKOUT_DURATION_SEC) {
            return true;
        }
        /* Lockout expired, reset attempts */
        g_session.auth_attempt_count = 0;
        g_session.lockout_start_time = 0;
    }
    return false;
}

static bool session_check_timeout(void) {
    if (g_session.auth_state != AUTH_STATE_AUTHENTICATED) {
        return false;
    }

    uint32_t now = platform_get_time_sec();
    uint32_t elapsed = now - g_session.last_activity_time;

    if (elapsed > DIAG_SESSION_TIMEOUT_SEC) {
        audit_log(AUDIT_SESSION_TIMEOUT, 0);
        diag_print("\r\n[SESSION EXPIRED]\r\n");

        /* If JTAG was unlocked, re-lock it */
        if (g_session.jtag_unlocked) {
            platform_jtag_disable();
            audit_log(AUDIT_JTAG_LOCK, 0);
        }

        session_reset();
        return true;
    }
    return false;
}

static void session_update_activity(void) {
    g_session.last_activity_time = platform_get_time_sec();
}

