static int cmd_auth(int argc, const char *argv[]) {
    if (argc < 2) {
        diag_print("Usage: auth challenge | auth response <hmac_hex> <priv_level>\r\n");
        return -1;
    }

    if (strcmp(argv[1], "challenge") == 0) {
        return auth_generate_challenge();
    } else if (strcmp(argv[1], "response") == 0) {
        if (argc < 4) {
            diag_print("Usage: auth response <hmac_hex> <priv_level>\r\n");
            return -1;
        }
        return auth_verify_response(argv[2], argv[3]);
    } else {
        diag_print("ERROR: Unknown auth subcommand\r\n");
        return -1;
    }
}

static int cmd_logout(int argc, const char *argv[]) {
    (void)argc; (void)argv;

    if (g_session.jtag_unlocked) {
        platform_jtag_disable();
        g_session.jtag_unlocked = false;
        audit_log(AUDIT_JTAG_LOCK, 0);
    }

    audit_log(AUDIT_CMD_EXECUTED, 0);
    session_full_reset();
    diag_print("OK: Logged out\r\n");
    return 0;
}

