static int cmd_dump_memory(int argc, const char *argv[]) {
    uint32_t addr, len;

    if (argc < 3) {
        diag_print("Usage: dump_memory <hex_addr> <length>\r\n");
        return -1;
    }

    if (safe_parse_uint32(argv[1], &addr) != 0) {
        diag_print("ERROR: Invalid address\r\n");
        return -1;
    }

    if (safe_parse_uint32(argv[2], &len) != 0) {
        diag_print("ERROR: Invalid length\r\n");
        return -1;
    }

    if (len == 0 || len > DIAG_MAX_DUMP_SIZE) {
        diag_print("ERROR: Length must be 1-");
        diag_print_uint32(DIAG_MAX_DUMP_SIZE);
        diag_print("\r\n");
        return -1;
    }

    if (!is_memory_access_allowed(addr, len, g_session.current_privilege)) {
        diag_print("ERROR: Access denied for region 0x");
        diag_print_hex_byte((uint8_t)(addr >> 24));
        diag_print_hex_byte((uint8_t)(addr >> 16));
        diag_print_hex_byte((uint8_t)(addr >> 8));
        diag_print_hex_byte((uint8_t)(addr));
        diag_print("\r\n");
        audit_log(AUDIT_CMD_DENIED, addr);
        return -1;
    }

    diag_print("Memory dump at 0x");
    diag_print_hex_byte((uint8_t)(addr >> 24));
    diag_print_hex_byte((uint8_t)(addr >> 16));
    diag_print_hex_byte((uint8_t)(addr >> 8));
    diag_print_hex_byte((uint8_t)(addr));
    diag_print(", ");
    diag_print_uint32(len);
    diag_print(" bytes:\r\n");

    /* Read and display memory in safe chunks */
    const uint8_t *ptr = (const uint8_t *)(uintptr_t)addr;
    uint8_t line_buf[16];
    uint32_t remaining = len;
    uint32_t offset = 0;

    while (remaining > 0) {
        uint32_t chunk = (remaining > 16) ? 16 : remaining;

        /* Copy to local buffer to avoid repeated volatile reads */
        for (uint32_t i = 0; i < chunk; i++) {
            line_buf[i] = ptr[offset + i];
        }

        /* Print address */
        uint32_t line_addr = addr + offset;
        diag_print_hex_byte((uint8_t)(line_addr >> 24));
        diag_print_hex_byte((uint8_t)(line_addr >> 16));
        diag_print_hex_byte((uint8_t)(line_addr >> 8));
        diag_print_hex_byte((uint8_t)(line_addr));
        diag_print(": ");

        diag_print_hex(line_buf, chunk);

        offset += chunk;
        remaining -= chunk;
    }

    return 0;
}

static int cmd_read_flash(int argc, const char *argv[]) {
    uint32_t addr, len;

    if (argc < 3) {
        diag_print("Usage: read_flash <hex_addr> <length>\r\n");
        return -1;
    }

    if (safe_parse_uint32(argv[1], &addr) != 0) {
        diag_print("ERROR: Invalid address\r\n");
        return -1;
    }

    if (safe_parse_uint32(argv[2], &len) != 0) {
        diag_print("ERROR: Invalid length\r\n");
        return -1;
    }

    if (len == 0 || len > DIAG_MAX_DUMP_SIZE) {
        diag_print("ERROR: Length must be 1-");
        diag_print_uint32(DIAG_MAX_DUMP_SIZE);
        diag_print("\r\n");
        return -1;
    }

    if (!is_memory_access_allowed(addr, len, g_session.current_privilege)) {
        diag_print("ERROR: Flash region access denied\r\n");
        audit_log(AUDIT_CMD_DENIED, addr);
        return -1;
    }

    uint8_t buf[DIAG_MAX_DUMP_SIZE];
    if (platform_flash_read(addr, buf, len) != 0) {
        diag_print("ERROR: Flash read failed\r\n");
        return -1;
    }

    diag_print("Flash at 0x");
    diag_print_hex_byte((uint8_t)(addr >> 24));
    diag_print_hex_byte((uint8_t)(addr >> 16));
    diag_print_hex_byte((uint8_t)(addr >> 8));
    diag_print_hex_byte((uint8_t)(addr));
    diag_print(":\r\n");
    diag_print_hex(buf, len);

    platform_secure_memzero(buf, sizeof(buf));
    return 0;
}

static int cmd_jtag_unlock(int argc, const char *argv[]) {
    (void)argc; (void)argv;

    if (g_session.current_privilege < PRIV_SERVICE) {
        diag_print("ERROR: Insufficient privilege for JTAG unlock\r\n");
        audit_log(AUDIT_CMD_DENIED, 0);
        return -1;
    }

    if (g_session.jtag_unlocked) {
        diag_print("JTAG already unlocked\r\n");
        return 0;
    }

    platform_jtag_enable();
    g_session.jtag_unlocked = true;
    g_session.jtag_unlock_time = platform_get_time_sec();

    audit_log(AUDIT_JTAG_UNLOCK, 0);

    diag_print("WARNING: JTAG enabled. Will auto-disable on session timeout.\r\n");
    diag_print("Use 'jtag_lock' to disable manually.\r\n");

    return 0;
}

static int cmd_jtag_lock(int argc, const char *argv[]) {
    (void)argc; (void)argv;

    platform_jtag_disable();
    g_session.jtag_unlocked = false;

    audit_log(AUDIT_JTAG_LOCK, 0);
    diag_print("OK: JTAG disabled\r\n");

    return 0;
}

static int cmd_audit_log(int argc, const char *argv[]) {
    (void)argc; (void)argv;

    static const char *event_names[] = {
        "AUTH_ATTEMPT", "AUTH_SUCCESS", "AUTH_FAILURE", "AUTH_LOCKOUT",
        "CMD_EXEC", "CMD_DENIED", "SESSION_TIMEOUT", "JTAG_UNLOCK", "JTAG_LOCK"
    };

    uint32_t count = g_audit_write_idx;
    if (count > DIAG_AUDIT_LOG_MAX_ENTRIES) {
        count = DIAG_AUDIT_LOG_MAX_ENTRIES;
    }

    uint32_t start = 0;
    if (g_audit_write_idx > DIAG_AUDIT_LOG_MAX_ENTRIES) {
        start = g_audit_write_idx - DIAG_AUDIT_LOG_MAX_ENTRIES;
    }

    diag_print("Audit Log (");
    diag_print_uint32(count);
    diag_print(" entries):\r\n");

    for (uint32_t i = start; i < g_audit_write_idx; i++) {
        uint32_t idx = i % DIAG_AUDIT_LOG_MAX_ENTRIES;
        audit_entry_t *e = &g_audit_ring[idx];

        diag_print("  T=");
        diag_print_uint32(e->timestamp);
        diag_print(" ");

        if (e->event <= AUDIT_JTAG_LOCK) {
            diag_print(event_names[e->event]);
        } else {
            diag_print("UNKNOWN");
        }

        diag_print(" detail=");
        diag_print_uint32(e->detail);
        diag_print(" sid=");
        diag_print_hex(e->session_id, 4);
    }

    return 0;
}

/*============================================================================
 * Command Parser and Dispatcher
 *============================================================================*/

static int parse_command(char *input, const char **argv, int max_args) {
    int argc = 0;
    char *p = input;
    bool in_token = false;

    while (*p != '\0' && argc < max_args) {
        if (*p == ' ' || *p == '\t' || *p == '\r' || *p == '\n') {
            *p = '\0';
            in_token = false;
        } else if (!in_token) {
            /* Validate character is printable ASCII */
            if (*p < 0x20 || *p > 0x7E) {
                return -1; /* Invalid character */
            }
            argv[argc++] = p;
            in_token = true;
        } else {
            if (*p < 0x20 || *p > 0x7E) {
                return -1;
            }
        }
        p++;
    }

    return argc;
}

static void dispatch_command(char *input) {
    const char *argv[DIAG_MAX_ARGS];
    int argc;

    /* Check session timeout before processing */
    if (session_check_timeout()) {
        return;
    }

    argc = parse_command(input, argv, DIAG_MAX_ARGS);
    if (argc <= 0) {
        return;
    }

    /* Validate command length */
    if (strlen(argv[0]) > DIAG_MAX_ARG_LEN) {
        diag_print("ERROR: Command too long\r\n");
        return;
    }

    /* Look up command in allowlist */
    const diag_command_t *cmd = NULL;
    int cmd_idx = -1;
    for (int i = 0; g_commands[i].name != NULL; i++) {
        if (strcmp(argv[0], g_commands[i].name) == 0) {
            cmd = &g_commands[i];
            cmd_idx = i;
            break;
        }
    }

    if (cmd == NULL) {
        diag_print("ERROR: Unknown command. Type 'help' for available commands.\r\n");
        return;
    }

    /* Check privilege level */
    if (g_session.current_privilege < cmd->required_privilege) {
        diag_print("ERROR: Insufficient privilege (need level ");
        diag_print_uint32(cmd->required_privilege);
        diag_print(", have ");
        diag_print_uint32(g_session.current_privilege);
        diag_print(")\r\n");
        audit_log(AUDIT_CMD_DENIED, (uint32_t)cmd_idx);
        return;
    }

    /* Update session activity timestamp */
    session_update_activity();

    /* Execute command */
    audit_log(AUDIT_CMD_EXECUTED, (uint32_t)cmd_idx);
    int result = cmd->handler(argc, argv);

    if (result != 0) {
        diag_print("Command returned error ");
        diag_print_uint32((uint32_t)(-result));
        diag_print("\r\n");
    }
}

/*============================================================================
 * Input Processing
 *============================================================================*/

static void process_input_byte(uint8_t byte) {
    /* Handle backspace */
    if (byte == 0x08 || byte == 0x7F) {
        if (g_cmd_buffer_pos > 0) {
            g_cmd_buffer_pos--;
            /* Echo backspace */
            uint8_t bs_seq[] = { 0x08, ' ', 0x08 };
            platform_uart_send(bs_seq, 3);
        }
        return;
    }

    /* Handle enter */
    if (byte == '\r' || byte == '\n') {
        diag_print("\r\n");
        g_cmd_buffer[g_cmd_buffer_pos] = '\0';

        if (g_cmd_buffer_pos > 0) {
            dispatch_command(g_cmd_buffer);
        }

        g_cmd_buffer_pos = 0;
        memset(g_cmd_buffer, 0, sizeof(g_cmd_buffer));

        /* Print prompt */
        if (g_session.auth_state == AUTH_STATE_AUTHENTICATED) {
            diag_print("diag> ");
        } else {
            diag_print("locked> ");
        }
        return;
    }

    /* Only accept printable ASCII */
    if (byte < 0x20 || byte > 0x7E) {
        return;
    }

    /* Buffer overflow protection */
    if (g_cmd_buffer_pos >= DIAG_MAX_CMD_LEN) {
        diag_print("\r\nERROR: Input too long\r\n");
        g_cmd_buffer_pos = 0;
        memset(g_cmd_buffer, 0, sizeof(g_cmd_buffer));
        return;
    }

    g_cmd_buffer[g_cmd_buffer_pos++] = (char)byte;

    /* Echo character (but not for auth response to avoid shoulder surfing) */
    /* In a real implementation, you might suppress echo during auth */
    platform_uart_send(&byte, 1);
}

/*============================================================================
 * Public API
 *============================================================================*/

/**
 * Initialize the diagnostic console.
 * Call once during system startup.
 */
int diag_console_init(void) {
    /* Initialize session state */
    session_full_reset();

    /* Clear command buffer */
    memset(g_cmd_buffer, 0, sizeof(g_cmd_buffer));
    g_cmd_buffer_pos = 0;

    /* Clear audit log */
    memset(g_audit_ring, 0, sizeof(g_audit_ring));
    g_audit_write_idx = 0;

    /* Disable JTAG by default */
    platform_jtag_disable();

    /* Initialize UART */
    if (platform_uart_init(DIAG_UART_BAUD_RATE) != 0) {
        return -1;
    }

    diag_print("\r\n");
    diag_print("========================================\r\n");
    diag_print("  Industrial IoT Sensor Diagnostic Console\r\n");
    diag_print("  Authentication required for access.\r\n");
    diag_print("  Type 'help' for available commands.\r\n");
    diag_print("========================================\r\n");
    diag_print("locked> ");

    return 0;
}

/**
 * Process incoming UART data.
 * Call this from the main loop or UART interrupt handler.
 */
void diag_console_poll(void) {
    uint8_t byte;

    /* Check for session timeout periodically */
    session_check_timeout();

    /* Check if JTAG should be auto-locked */
    if (g_session.jtag_unlocked &&
        g_session.auth_state != AUTH_STATE_AUTHENTICATED) {
        platform_jtag_disable();
        g_session.jtag_unlocked = false;
        audit_log(AUDIT_JTAG_LOCK, 0);
    }

    /* Try to receive a byte with short timeout */
    if (platform_uart_receive_byte(&byte, 10) == 0) {
        process_input_byte(byte);
    }
}

